#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int64_t X,R,M; scanf("%" PRId64 " %" PRId64 " %" PRId64, &X, &R, &M);
        int64_t total = M * 60LL;
        int64_t need = R * 60LL;
        int64_t maxRun;
        if(total <= X) maxRun = total;
        else maxRun = X + (total - X) / 2;
        printf("%s\n", (need <= maxRun) ? "YES" : "NO");
    }
    return 0;
}

