#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        X = int(next(it)); R = int(next(it)); M = int(next(it))
        total = M * 60
        need = R * 60
        if total <= X:
            max_run = total
        else:
            max_run = X + (total - X) // 2
        out.append('YES' if need <= max_run else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

